package com.program;

public class Ifcondition {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int num = -10;
		if (num > 0) {
			System.out.println(num + " is Positive");
		}
		else if(num<0)
		{
			System.out.println(num + " is Negative");
		}
		else
		{
			System.out.println(num + " is zero");
		}
	}

}
